#include <stdio.h>

int isLeap(int y) {
    return (y % 400 == 0) || (y % 4 == 0 && y % 100 != 0);
}

int main() {
    int T, N;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d", &N);
        int y = N + 1;
        while (!isLeap(y)) ++y;
        printf("%d\n", y);
    }
    return 0;
}

